This Verilog module:
```
module our(in1, in2, out);
        input wire[1:0] in1;
        input wire[1:0] in2;
        output wire[1:0] out;

        assign out = in1 & in2; 

        initial begin $display("Hello World"); $finish; end
endmodule
```
can only produce 2 bits.

Howerer, this C++ program:
```
#include "Vour.h"
#include "verilated.h"
        
int main(int argc, char** argv) {
    VerilatedContext* contextp = new VerilatedContext;
    contextp->commandArgs(argc, argv);

    Vour* top = new Vour{contextp};
    top->in1 = 4+1;
    top->in2 = 4+3;
    top->out = 0;

    printf("> out=0x%x\n", top->out);
    while (!contextp->gotFinish()) {
        top->eval();
    }
    printf("< out=0x%x\n", top->out);

    delete top;
    delete contextp;

    return 0;
}
```
prints
```
> out=0x0
Hello World
- our.v:8: Verilog $finish
< out=0x5
```
which has the third bit set in the output which wasn't set before the call.
